{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日付で正式キックオフし、正式発足とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "主要画面の応答時間目標を1.2秒以内とする",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D3",
      "content": "週次定例は毎週水曜日10時からの1時間枠で開催し、各部署から少なくとも1名が参加し、リモート参加も可とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "認証とマスタ配信はサクラ商事さんとの共同利用案で進める",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "第1フェーズではトランザクション系データを移行せず、旧システムを参照用に残す",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "負荷テストは専用の実行環境を新たに構築して実施する",
      "decided_by": "沼田 賢一"
    },
    {
      "id": "D7",
      "content": "既存のロール定義を流用し、新規設計は行わない",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D8",
      "content": "障害時の一次受け窓口はQAチームとする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "移行方式は拠点を分けて順次切り替える段階移行とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D10",
      "content": "本番リリース目標日は2026-10-15とする",
      "decided_by": "桐生 遥"
    }
  ],
